package com.establo.service;
import com.establo.dto.ReservationDto;import com.establo.entity.Reservation;import com.establo.exception.*;import com.establo.repository.ReservationRepository;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.LocalDate;import java.util.List;
@Service @RequiredArgsConstructor public class ReservationService {
 private final ReservationRepository repo;private final HorseService horses;public List<ReservationDto> all(){return repo.findAll().stream().map(this::dto).toList();}@Transactional public ReservationDto create(ReservationDto d){validate(d,null);return dto(repo.save(apply(new Reservation(),d)));}@Transactional public ReservationDto update(Long id,ReservationDto d){var r=entity(id);validate(d,r);return dto(repo.save(apply(r,d)));}@Transactional public void cancel(Long id){var r=entity(id);r.setStatus("CANCELLED");repo.save(r);}
 public Page<ReservationDto> search(String q,String type,LocalDate date,Pageable pageable){var filtered=all().stream().filter(r->q==null||q.isBlank()||(r.horseName()+" "+r.responsible()+" "+r.activityType()).toLowerCase().contains(q.toLowerCase())).filter(r->type==null||type.isBlank()||r.activityType().equalsIgnoreCase(type)).filter(r->date==null||r.startAt().toLocalDate().equals(date)).toList();int start=(int)Math.min(pageable.getOffset(),filtered.size());int end=Math.min(start+pageable.getPageSize(),filtered.size());return new PageImpl<>(filtered.subList(start,end),pageable,filtered.size());}
 private void validate(ReservationDto d,Reservation current){if(!d.endAt().isAfter(d.startAt()))throw new BusinessException("La hora final debe ser posterior a la inicial");int capacity=d.capacity()==null?1:d.capacity();int participants=d.participants()==null?1:d.participants();if(participants>capacity)throw new BusinessException("El cupo solicitado supera la capacidad disponible");boolean conflict=current==null?repo.existsByHorseIdAndStatusNotAndStartAtLessThanAndEndAtGreaterThan(d.horseId(),"CANCELLED",d.endAt(),d.startAt()):repo.existsByHorseIdAndStatusNotAndIdNotAndStartAtLessThanAndEndAtGreaterThan(d.horseId(),"CANCELLED",current.getId(),d.endAt(),d.startAt());if(conflict)throw new BusinessException("El caballo ya tiene una reserva en ese horario");}
 private Reservation entity(Long id){return repo.findById(id).orElseThrow(()->new ResourceNotFoundException("Reserva no encontrada"));}private Reservation apply(Reservation r,ReservationDto d){r.setHorse(horses.entity(d.horseId()));r.setStartAt(d.startAt());r.setEndAt(d.endAt());r.setActivityType(d.activityType());r.setResponsible(d.responsible());r.setStatus(d.status()==null?"SCHEDULED":d.status());r.setObservations(d.observations());r.setCapacity(d.capacity()==null?1:d.capacity());r.setParticipants(d.participants()==null?1:d.participants());return r;}private ReservationDto dto(Reservation r){return new ReservationDto(r.getId(),r.getHorse().getId(),r.getHorse().getName(),r.getStartAt(),r.getEndAt(),r.getActivityType(),r.getResponsible(),r.getStatus(),r.getObservations(),r.getCapacity()==null?1:r.getCapacity(),r.getParticipants()==null?1:r.getParticipants());}
}
